public void test_InetAddress() throws Exception {
    JDKStringConverter test = JDKStringConverter.INET_ADDRESS;
    doTest0(test, InetAddress.class, InetAddress.getByName("1.2.3.4"), "1.2.3.4");

    InetAddress obj = InetAddress.getByName("2001:0db8:85a3:0000:0000:8a2e:0370:7334");
    String str = test.convertToString(obj);
    assertTrue(
            str.equals("2001:db8:85a3:0:0:8a2e:370:7334")
                    || str.equals("2001:db8:85a3::8a2e:370:7334"));
    assertEquals(obj, test.convertFromString(InetAddress.class, str));
    assertEquals(
            obj, test.convertFromString(InetAddress.class, "2001:db8:85a3:0:0:8a2e:370:7334"));
    assertEquals(
            obj, test.convertFromString(InetAddress.class, "2001:db8:85a3::8a2e:370:7334"));
}

