public void doTest1(
        JDKStringConverter test, Class<?> cls, Object obj, String str, Object objFromStr) {
    assertEquals(cls, test.getType());
    assertEquals(str, test.convertToString(obj));
    assertEquals(objFromStr, test.convertFromString(cls, str));
}

public void doTest0(JDKStringConverter test, Class<?> cls, Object obj, String str) {
    doTest1(test, cls, obj, str, obj);
}

